glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform vec3 baseColor;
uniform vec3 warmA;
uniform vec3 warmB;
uniform float noiseScale;
uniform float grain;
float hash(vec2 p){ return fract(sin(dot(p, vec2(127.1,311.7))) * 43758.5453123); }
float noise(vec2 p){
 vec2 i = floor(p);
 vec2 f = fract(p);
 f = f * f * (3.0 - 2.0 * f);
 float a = hash(i);
 float b = hash(i + vec2(1.0,0.0));
 float c = hash(i + vec2(0.0,1.0));
 float d = hash(i + vec2(1.0,1.0));
 return mix(mix(a,b,f.x), mix(c,d,f.x), f.y);
}
void main(){
 vec2 p = vUv;
 float vertical = smoothstep(0.0, 1.0, p.y);
 float cloud = noise(p * noiseScale) * 0.55 + noise((p + vec2(2.1,1.7)) * noiseScale * 2.0) * 0.25;
 float warmBand = smoothstep(0.18, 0.92, 1.0 - abs(p.x - 0.5) * 1.15);
 vec3 col = mix(baseColor, warmA, 0.22 + 0.18 * vertical + 0.16 * cloud);
 col = mix(col, warmB, 0.10 * warmBand * (0.4 + 0.6 * cloud));
 float g = (hash(gl_FragCoord.xy) - 0.5) * grain;
 col += g;
 gl_FragColor = vec4(col, 1.0);
}

