glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform vec3 primary;
uniform vec3 secondary;
uniform vec3 glow;
uniform float height;
uniform float width;
float ellipse(vec2 p, vec2 r){
 return length(p / r);
}
float spindleShell(vec2 p, float y0, float ry, float rx, float edge){
 float d = ellipse(p - vec2(0.0, y0), vec2(rx, ry));
 return 1.0 - smoothstep(1.0 - edge, 1.0 + edge, d);
}
void main(){
 vec2 p = vUv * 2.0 - 1.0;
 p.y *= 1.18;
 float taper = 1.0 - min(1.0, abs(p.y) * 0.72);
 float body = 0.0;
 float rings = 0.0;
 for(int i=0;i<9;i++){
 float fi = float(i) / 8.0;
 float y0 = mix(-0.72, 0.72, fi);
 float ry = mix(0.16, 0.11, abs(fi - 0.5) * 1.3);
 float rx = mix(0.12, 0.28, 1.0 - abs(fi - 0.5) * 1.45) * taper + 0.03;
 float shell = spindleShell(p, y0, ry, rx, 0.05);
 float inner = spindleShell(p, y0, ry * 0.72, max(0.02, rx * 0.72), 0.06);
 body = max(body, shell);
 rings += max(0.0, shell - inner);
 }
 float spine = 1.0 - smoothstep(0.018, 0.055, abs(p.x) * (1.0 + abs(p.y) * 0.2));
 float capTop = spindleShell(p, 0.92, 0.14, 0.11, 0.05);
 float capBottom = spindleShell(p, -0.92, 0.14, 0.11, 0.05);
 body = max(body, max(capTop, capBottom));
 float goldLine = smoothstep(0.72, 1.0, rings) * 0.28 + spine * 0.18;
 vec3 col = mix(vec3(0.0), primary, body * 0.88);
 col = mix(col, secondary, clamp(rings * 0.72, 0.0, 1.0));
 col += glow * goldLine;
 float alpha = clamp(body * 0.96 + spine * 0.18, 0.0, 1.0);
 gl_FragColor = vec4(col, alpha);
}

