glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform vec3 primary;
uniform vec3 secondary;
uniform float opacity;
uniform float sideSign;
float petal(vec2 p, vec2 c, vec2 r){
 vec2 q = p - c;
 q.x *= 1.0 + 0.4 * abs(q.y);
 return 1.0 - smoothstep(0.9, 1.08, length(q / r));
}
void main(){
 vec2 p = vUv * 2.0 - 1.0;
 float a = petal(p, vec2(-0.48 * sideSign, 0.16), vec2(0.42, 0.56));
 float b = petal(p, vec2(-0.43 * sideSign, -0.28), vec2(0.34, 0.44));
 float c = petal(p, vec2(-0.31 * sideSign, 0.56), vec2(0.24, 0.22));
 float shape = max(a, max(b, c));
 float innerLean = smoothstep(0.52, 0.06, abs(p.x + 0.12 * sideSign));
 vec3 col = mix(secondary, primary, 0.58 + 0.22 * p.y);
 col *= 0.92 + 0.08 * innerLean;
 gl_FragColor = vec4(col, shape * opacity);
}

