glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform vec3 anchor;
uniform vec3 glow;
uniform vec3 primary;
void main(){
 vec2 p = vUv * 2.0 - 1.0;
 float oval = length(vec2(p.x / 0.62, p.y / 0.92));
 float halo = 1.0 - smoothstep(0.92, 1.08, oval);
 float slit = 1.0 - smoothstep(0.08, 0.22, length(vec2(p.x / 0.18, p.y / 0.72)));
 float core = (1.0 - smoothstep(0.04, 0.12, abs(p.x))) * (1.0 - smoothstep(0.74, 0.98, abs(p.y)));
 vec3 col = anchor * core + glow * halo * 0.42;
 col += primary * slit * 0.06;
 float alpha = max(halo * 0.42, core);
 gl_FragColor = vec4(col, alpha);
}

