glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform vec3 stroke;
uniform float opacity;
float arcStroke(vec2 p, vec2 c, vec2 r, float width, float a0, float a1){
 vec2 q = p - c;
 float ang = atan(q.y, q.x);
 float d = abs(length(q / r) - 1.0);
 float mask = smoothstep(width, width * 0.2, d);
 float gate = step(a0, ang) * step(ang, a1);
 return mask * gate;
}
void main(){
 vec2 p = vUv * 2.0 - 1.0;
 float s = 0.0;
 s += arcStroke(p, vec2(-0.12, 0.18), vec2(0.56, 0.34), 0.035, -0.2, 1.9);
 s += arcStroke(p, vec2(0.14, -0.06), vec2(0.48, 0.28), 0.028, 1.7, 3.8);
 s += arcStroke(p, vec2(-0.04, -0.36), vec2(0.34, 0.18), 0.024, -0.4, 1.3);
 s += arcStroke(p, vec2(0.22, 0.42), vec2(0.26, 0.14), 0.022, 2.4, 4.1);
 gl_FragColor = vec4(stroke, min(1.0, s) * opacity);
}
